function getSavedSalons(){
  try {
    const val = localStorage.getItem('trimora_saved_salons');
    return val ? JSON.parse(val) : [];
  } catch (e) {
    return [];
  }
}

function updateSaveButtonUI(){
  if(!selectedSalon) return;
  const saved=getSavedSalons();
  const isSaved=saved.includes(selectedSalon.id);
  const icon=document.getElementById('detailSaveIcon');
  const label=document.getElementById('detailSaveLabel');
  const container=document.getElementById('detailSaveIconContainer');
  if(icon&&label){
    if(isSaved){
      icon.className="fa-solid fa-bookmark text-xs";
      label.innerText=currentLang==='en'?"SAVED":"सहेजा गया";
      if(container)container.classList.add('text-amber-450');
    }else{
      icon.className="fa-regular fa-bookmark text-xs";
      label.innerText=currentLang==='en'?"SAVE":"सहेजें";
      if(container)container.classList.remove('text-amber-450');
    }
  }
}

function toggleSaveSalon(){
  if(!selectedSalon) return;
  const saved=getSavedSalons();
  const idx=saved.indexOf(selectedSalon.id);
  if(idx===-1){
    saved.push(selectedSalon.id);
  }else{
    saved.splice(idx,1);
  }
  localStorage.setItem('trimora_saved_salons',JSON.stringify(saved));
  updateSaveButtonUI();
}

function shareSalonLink(){
  if(!selectedSalon) return;
  const shareUrl=`${window.location.origin}${window.location.pathname}?salon=${selectedSalon.id}`;
  navigator.clipboard.writeText(shareUrl).then(()=>{
    alert(currentLang==='en'?"Salon link copied to clipboard!":"सैलून लिंक क्लिपबोर्ड पर कॉपी हो गया!");
  }).catch(err=>{
    console.error("Could not copy: ",err);
    alert(shareUrl);
  });
}

