function handleSearchInput(query){
  const searchSug=document.getElementById('searchSuggestions');
  const clearBtn=document.getElementById('clearSearchBtn');
  const noRes=document.getElementById('searchNoResults');
  if(!query.trim()){
    clearSearch();
    return;
  }
  if(clearBtn)clearBtn.classList.remove('hidden');
  const filtered=salonsData.filter(s=>s.status!=='pending'&&(s.name.toLowerCase().includes(query.toLowerCase())||s.address.toLowerCase().includes(query.toLowerCase())));
  renderSalonsList(filtered);
  if(!searchSug)return;
  searchSug.innerHTML='';
  if(filtered.length===0){
    searchSug.classList.add('hidden');
    if(noRes){
      noRes.innerText=t('searchNoResults').replace('{query}',query);
      noRes.classList.remove('hidden');
    }
    return;
  }
  if(noRes)noRes.classList.add('hidden');
  searchSug.classList.remove('hidden');
  filtered.forEach(s=>{
    const div=document.createElement('div');
    div.className="px-3 py-2 text-xs text-slate-355 hover:bg-slate-800 hover:text-white cursor-pointer transition-colors border-b border-slate-850/50 flex justify-between items-center";
    div.innerHTML=`<span>${s.name} <span class="text-[10px] text-slate-500">(${s.address.split(',')[0]})</span></span><span class="text-[9px] text-brand-400 font-semibold">${getSalonStatus(s)}</span>`;
    div.onclick=()=>{
      selectSalonFromList(s.id);
      document.getElementById('salonSearchInput').value=s.name;
      searchSug.classList.add('hidden');
    };
    searchSug.appendChild(div);
  });
}

function initMap(){
  try {
    if (typeof L === 'undefined') {
      console.warn("Leaflet (L) is not defined. Map cannot be initialized.");
      const mapEl = document.getElementById('map');
      if (mapEl) mapEl.classList.add('hidden');
      return;
    }
    if(map)return;
    map=L.map('map',{zoomControl:false}).setView([29.1492,75.7217],13);
    L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png',{maxZoom:20}).addTo(map);
    L.control.zoom({position:'bottomright'}).addTo(map);
    renderMapMarkers(salonsData.filter(s=>s.status!=='pending'));
    setTimeout(()=>{
      if(map && mapMarkers.length>0){
        const group=new L.featureGroup(mapMarkers);
        map.fitBounds(group.getBounds().pad(0.1));
      }
    },200);
  } catch (e) {
    console.error("Error in initMap:", e);
    const mapEl = document.getElementById('map');
    if (mapEl) mapEl.classList.add('hidden');
  }
}

function renderMapMarkers(salonsList){
  if (typeof L === 'undefined' || !map) return;
  try {
    mapMarkers.forEach(m=>map.removeLayer(m));
    mapMarkers=[];
    salonsList.forEach(salon=>{
      const status=getSalonStatus(salon);
      const isClosed=status==='closed';
      const color=isClosed?'#ef4444':(status==='full'?'#f97316':(status==='busy'?'#f59e0b':'#10b981'));
      const customIcon=L.divIcon({className:'custom-div-icon',html:`<div class="flex items-center justify-center w-7 h-7 rounded-full shadow-lg border-2 border-slate-900 p-0.5" style="background-color:${color};"><img src="images/logo_symbol_trans.png?v=1.2" class="w-full h-full object-contain"></div>`,iconSize:[28,28],iconAnchor:[14,14]});
      const distanceStr=getDistanceString(salon.coords);
      const statusText=isClosed?(currentLang==='en'?'Closed':'बंद'):(status==='full'?t('highDemandStatus'):(status==='busy'?t('standardStatus'):t('fastPassStatus')));
      const popupContent=`<div class="p-1 space-y-1 max-w-[200px] text-slate-100"><h4 class="font-bold font-outfit text-xs text-white">${salon.name}</h4><p class="text-[10px] text-slate-400">${salon.address}</p><p class="text-[10px]" style="color:${color}; font-weight:bold;">${statusText}</p><p class="text-[10px] font-bold text-brand-400 flex items-center space-x-1"><i class="fa-solid fa-location-dot"></i><span>${distanceStr}</span></p></div>`;
      const marker=L.marker(salon.coords,{icon:customIcon}).addTo(map).bindPopup(popupContent);
      marker.salonId=salon.id;
      marker.on('click',()=>{selectSalonFromList(salon.id,false)});
      marker.on('mouseover',function(){this.openPopup()});
      mapMarkers.push(marker);
    });
  } catch (e) {
    console.error("Error in renderMapMarkers:", e);
  }
}

