let ringtoneInterval=null;
let callAnswerTimeout=null;
let callAutoHangupTimeout=null;
let isCallAnswered=false;

function triggerVoiceCallAlert(token, waitTime){
  const overlay=document.getElementById('phoneCallOverlay');
  const statusText=document.getElementById('callStatusText');
  const wave=document.getElementById('callWaveform');
  const salonNameEl=document.getElementById('callSalonName');
  const snippetEl=document.getElementById('callMessageSnippet');
  if(!overlay)return;
  if(window.speechSynthesis&&window.speechSynthesis.cancel)window.speechSynthesis.cancel();
  if(callAnswerTimeout)clearTimeout(callAnswerTimeout);
  if(callAutoHangupTimeout)clearTimeout(callAutoHangupTimeout);
  if(ringtoneInterval)clearInterval(ringtoneInterval);
  isCallAnswered=false;
  salonNameEl.innerText=token.salonName;
  overlay.classList.remove('hidden');
  statusText.innerText=currentLang==='en'?"Ringing...":"घंटी बज रही है...";
  wave.classList.add('opacity-0');
  snippetEl.innerText="";
  const waitVal = waitTime !== undefined ? waitTime : token.remainingWait;
  const waitMins=waitVal.toFixed(0);
  const travelMins=token.travelTime;
  let textEn, textHi;
  if (waitVal <= 0.1) {
    textEn = `Hello! This is a call from ZeroWait Q. Your appointment at ${token.salonName} has started. Please proceed to the salon chair immediately. Thank you!`;
    textHi = `नमस्ते! यह जीरोवेट क्यू से एक कॉल है। ${token.salonName} पर आपकी बारी शुरू हो गई है। कृपया तुरंत सैलून पहुंचें। धन्यवाद!`;
  } else {
    textEn = `Hello! This is a call from ZeroWait Q. Your appointment at ${token.salonName} is starting soon. Your wait time is ${waitMins} minutes, which matches your travel time of ${travelMins} minutes. Please start traveling now. Thank you!`;
    textHi = `नमस्ते! यह जीरोवेट क्यू से एक कॉल है। ${token.salonName} पर आपका अपॉइंटमेंट जल्द ही शुरू होने वाला है। आपकी प्रतीक्षा का समय ${waitMins} मिनट है, जो आपके यात्रा समय ${travelMins} मिनट के बराबर है। कृपया अभी निकलें। धन्यवाद!`;
  }
  const speechText=currentLang==='en'?textEn:textHi;
  window.currentSpeechText=speechText;
  
  // Play ringtone immediately
  try { playSound('alert'); } catch(e) {}
  // Play ringtone every 2.5 seconds
  ringtoneInterval = setInterval(() => {
    try { playSound('alert'); } catch(e) {}
  }, 2500);

  // Auto decline if unanswered for 20 seconds
  callAutoHangupTimeout = setTimeout(() => {
    endSimulatedCall();
  }, 20000);
}

function acceptSimulatedCall(text){
  if(isCallAnswered)return;
  isCallAnswered=true;
  if(callAnswerTimeout)clearTimeout(callAnswerTimeout);
  if(callAutoHangupTimeout)clearTimeout(callAutoHangupTimeout);
  if(ringtoneInterval) {
    clearInterval(ringtoneInterval);
    ringtoneInterval = null;
  }
  const statusText=document.getElementById('callStatusText');
  const wave=document.getElementById('callWaveform');
  const snippetEl=document.getElementById('callMessageSnippet');
  if(statusText)statusText.innerText=currentLang==='en'?"Connected":"जुड़ा हुआ है";
  if(wave)wave.classList.remove('opacity-0');
  const speechText=text||window.currentSpeechText||"";
  if(snippetEl)snippetEl.innerText=`"${speechText}"`;
  if(typeof SpeechSynthesisUtterance==='undefined'||!window.speechSynthesis){
    callAutoHangupTimeout=setTimeout(()=>{
      hangupSimulatedCall();
    },6000);
  }else{
    const utterance=new SpeechSynthesisUtterance(speechText);
    utterance.lang=currentLang==='en'?'en-US':'hi-IN';
    utterance.onend=()=>{
      hangupSimulatedCall();
    };
    utterance.onerror=()=>{
      hangupSimulatedCall();
    };
    window.speechSynthesis.speak(utterance);
  }
}

function hangupSimulatedCall(){
  const statusText=document.getElementById('callStatusText');
  const wave=document.getElementById('callWaveform');
  const overlay=document.getElementById('phoneCallOverlay');
  if(statusText)statusText.innerText=currentLang==='en'?"Call Ended":"कॉल समाप्त";
  if(wave)wave.classList.add('opacity-0');
  if(ringtoneInterval) {
    clearInterval(ringtoneInterval);
    ringtoneInterval = null;
  }
  callAutoHangupTimeout=setTimeout(()=>{
    if(overlay)overlay.classList.add('hidden');
  },1500);
}

function endSimulatedCall(){
  if(window.speechSynthesis&&window.speechSynthesis.cancel)window.speechSynthesis.cancel();
  if(callAnswerTimeout)clearTimeout(callAnswerTimeout);
  if(callAutoHangupTimeout)clearTimeout(callAutoHangupTimeout);
  if(ringtoneInterval) {
    clearInterval(ringtoneInterval);
    ringtoneInterval = null;
  }
  isCallAnswered=false;
  hangupSimulatedCall();
}
