function getBarberRating(salonId,barberName){const reviews=historyData.filter(t=>t.status==='completed'&&t.feedback&&t.feedback.barberRating&&t.salonId===salonId&&t.barberName===barberName);const salon=salonsData.find(s=>s.id===salonId);const barber=salon?salon.barbers.find(b=>b.name===barberName):null;const defaultRating=barber?barber.rating:4.5;if(reviews.length===0)return defaultRating.toFixed(1);const sum=reviews.reduce((acc,r)=>acc+r.feedback.barberRating,0);return((defaultRating+sum)/(reviews.length+1)).toFixed(1)}
