function updateRewardOptionsDisabledState() {
  const rewardSelect = document.getElementById('ownerComboRewardInput');
  if (!rewardSelect) return;
  const checkedCheckboxes = document.querySelectorAll('#ownerComboTriggersContainer input[type="checkbox"]:checked');
  const checkedIds = Array.from(checkedCheckboxes).map(cb => cb.value);
  Array.from(rewardSelect.options).forEach(opt => {
    if (opt.value && checkedIds.includes(opt.value)) {
      opt.disabled = true;
      if (opt.selected) {
        rewardSelect.value = '';
      }
    } else {
      opt.disabled = false;
    }
  });
}
