async function renderOwnerAnalytics(){const tableBody=document.getElementById('barberAnalyticsTableBody');if(!tableBody)return;tableBody.innerHTML='';const activeSalonId=isSuperAdmin?(document.getElementById('ownerSalonSelector')?document.getElementById('ownerSalonSelector').value:null):loggedInSalonId;try{const res=await fetch('/api/barber-stats');const stats=await res.json();let mostActiveBarber="None",highestCount=0;const allBarbers=[];salonsData.forEach(s=>{if(!activeSalonId||s.id===activeSalonId){s.barbers.forEach(b=>{if(!allBarbers.some(exist=>exist.name===b.name))allBarbers.push(b)})}});let grandTotals={haircut:0,beard:0,facewash:0,massage:0,total:0};let tableRows='';allBarbers.forEach(barber=>{const barberStats=stats[barber.name]||{};const haircutCount=barberStats['haircut']||0,beardCount=barberStats['beard']||0,facewashCount=barberStats['facewash']||0,massageCount=barberStats['massage']||0,totalServed=haircutCount+beardCount+facewashCount+massageCount;grandTotals.haircut+=haircutCount;grandTotals.beard+=beardCount;grandTotals.facewash+=facewashCount;grandTotals.massage+=massageCount;grandTotals.total+=totalServed;if(totalServed>highestCount){highestCount=totalServed;mostActiveBarber=barber.name}tableRows+=`<tr class="border-b border-slate-800 text-[11px] text-slate-355 hover:bg-slate-900/40 transition-colors"><td class="py-2.5 pl-3 font-semibold text-white">${barber.name.split(' ')[0]}</td><td class="py-2.5 text-center">${haircutCount}</td><td class="py-2.5 text-center">${beardCount}</td><td class="py-2.5 text-center">${facewashCount}</td><td class="py-2.5 text-center">${massageCount}</td><td class="py-2.5 text-center font-bold text-brand-400 pr-3">${totalServed}</td></tr>`});tableRows+=`<tr class="text-[11px] font-bold text-slate-400 bg-slate-955/40"><td class="py-2.5 pl-3 text-slate-300">Total</td><td class="py-2.5 text-center">${grandTotals.haircut}</td><td class="py-2.5 text-center">${grandTotals.beard}</td><td class="py-2.5 text-center">${grandTotals.facewash}</td><td class="py-2.5 text-center">${grandTotals.massage}</td><td class="py-2.5 text-center text-brand-400 pr-3">${grandTotals.total}</td></tr>`;tableBody.innerHTML=tableRows;document.getElementById('ownerTotalBarbers').innerText=allBarbers.length;document.getElementById('ownerTotalServices').innerText=allBarbers.length*2;document.getElementById('ownerTotalCustomers').innerText=grandTotals.total;document.getElementById('mostActiveBarberVal').innerText=mostActiveBarber;const reviews=historyData.filter(t=>t.feedback&&(!activeSalonId||t.salonId===activeSalonId));let avgSalon=0,avgBarber=0;if(reviews.length>0){const sumSalon=reviews.reduce((sum,r)=>sum+r.feedback.salonRating,0);const sumBarber=reviews.reduce((sum,r)=>sum+r.feedback.barberRating,0);avgSalon=(sumSalon/reviews.length).toFixed(1);avgBarber=(sumBarber/reviews.length).toFixed(1)}const sEl=document.getElementById('ownerAvgSalonRating'),bEl=document.getElementById('ownerAvgBarberRating');if(sEl)sEl.innerText=reviews.length>0?`${avgSalon} / 5`:'0.0 / 5';if(bEl)bEl.innerText=reviews.length>0?`${avgBarber} / 5`:'0.0 / 5';const reviewsContainer=document.getElementById('ownerReviewsContainer');if(reviewsContainer){if(reviews.length===0){reviewsContainer.innerHTML=`<p class="text-[10px] text-slate-500 italic text-center py-2">${t('noReviews')}</p>`}else{let reviewsHtml='';reviews.forEach(r=>{const salonStars='★'.repeat(r.feedback.salonRating)+'☆'.repeat(5-r.feedback.salonRating);const barberStars='★'.repeat(r.feedback.barberRating)+'☆'.repeat(5-r.feedback.barberRating);const last4=r.mobile.slice(-4);reviewsHtml+=`<div class="bg-slate-950 p-2 rounded-xl border border-slate-900 space-y-1"><div class="flex justify-between items-center text-[9px] text-slate-500"><span>Token #${r.tokenNumber} (Mobile: ******${last4})</span><span>${r.dateString}</span></div><div class="flex justify-between items-center text-[10px] text-slate-350"><span>Salon: <span class="text-amber-400 font-bold">${salonStars}</span></span><span>Barber (${r.barberName.split(' ')[0]}): <span class="text-amber-400 font-bold">${barberStars}</span></span></div>${r.feedback.comment?`<p class="text-[10px] text-slate-400 italic bg-slate-900/30 p-1.5 rounded">"${r.feedback.comment}"</p>`:''}</div>`});reviewsContainer.innerHTML=reviewsHtml}}}catch(e){console.error(e)}}
