function setupMobileFormatting(){
  const ids = ['mobileNumberInput', 'regOwnerMobile', 'newBarberMobile', 'customerForgotMobile', 'customerRegisterMobile'];
  ids.forEach(id => {
    const el = document.getElementById(id);
    if (!el) return;
    el.addEventListener('input', () => {
      let val = el.value;
      let digits = val.replace(/\D/g, '');
      if (digits.startsWith('91') && digits.length === 12) {
        digits = digits.substring(2);
      } else if (digits.startsWith('0') && digits.length === 11) {
        digits = digits.substring(1);
      }
      if (digits.length > 10) {
        digits = digits.substring(0, 10);
      }
      if (el.value !== digits) {
        el.value = digits;
      }
    });
    el.addEventListener('paste', (e) => {
      e.preventDefault();
      let pasteData = (e.clipboardData || window.clipboardData).getData('text');
      let digits = pasteData.replace(/\D/g, '');
      if (digits.startsWith('91') && digits.length === 12) {
        digits = digits.substring(2);
      } else if (digits.startsWith('0') && digits.length === 11) {
        digits = digits.substring(1);
      }
      if (digits.length > 10) {
        digits = digits.substring(0, 10);
      }
      el.value = digits;
    });
  });
  setupEnterKeyTriggers();
}

function setupEnterKeyTriggers() {
  const pairs = [
    { inputIds: ['customerLoginIdentity', 'customerLoginPassword'], action: submitCustomerLogin },
    { inputIds: ['customerRegisterName', 'customerRegisterMobile', 'customerRegisterEmail', 'customerRegisterPassword'], action: submitCustomerRegister },
    { inputIds: ['customerForgotMobile'], action: submitForgotPasswordRequest },
    { inputIds: ['customerForgotOtp', 'customerForgotNewPassword', 'customerForgotConfirmPassword'], action: submitPasswordReset }
  ];
  pairs.forEach(pair => {
    pair.inputIds.forEach(id => {
      const el = document.getElementById(id);
      if (!el) return;
      el.addEventListener('keydown', (e) => {
        if (e.key === 'Enter') {
          e.preventDefault();
          if (typeof pair.action === 'function') pair.action();
        }
      });
    });
  });
}

let featuredSliderInterval = null;
let routingControl = null;
function startFeaturedSliderAutoPlay() {
  if (featuredSliderInterval) clearInterval(featuredSliderInterval);
  const slider = document.getElementById('featuredSalonsSlider');
  if (!slider) return;
  featuredSliderInterval = setInterval(() => {
    const slides = slider.querySelectorAll('.snap-start');
    if (slides.length <= 1) return;
    const slideWidth = slides[0].offsetWidth + 12;
    let nextScrollLeft = slider.scrollLeft + slideWidth;
    if (nextScrollLeft >= slider.scrollWidth - slider.clientWidth - 5) {
      slider.scrollTo({ left: 0, behavior: 'smooth' });
    } else {
      slider.scrollTo({ left: nextScrollLeft, behavior: 'smooth' });
    }
  }, 3000);
  slider.onmouseenter = () => clearInterval(featuredSliderInterval);
  slider.onmouseleave = () => startFeaturedSliderAutoPlay();
  slider.ontouchstart = () => clearInterval(featuredSliderInterval);
  slider.ontouchend = () => startFeaturedSliderAutoPlay();
}

function renderFeaturedSalonsSlider() {
  const slider = document.getElementById('featuredSalonsSlider');
  if (!slider) return;
  slider.innerHTML = '';
  const tierPriority = { gold: 1, silver: 2, bronze: 3 };
  const featured = salonsData.filter(s => s.adTier).sort((a, b) => (tierPriority[a.adTier] || 99) - (tierPriority[b.adTier] || 99));
  if (featured.length === 0) {
    slider.classList.add('hidden');
    if (featuredSliderInterval) {
      clearInterval(featuredSliderInterval);
      featuredSliderInterval = null;
    }
    return;
  }
  slider.classList.remove('hidden');
  featured.forEach(s => {
    const reviews = historyData.filter(t => t.salonId === s.id && t.feedback && t.feedback.salonRating);
    let avgRating = 0.0;
    if (reviews.length > 0) {
      const sum = reviews.reduce((acc, r) => acc + r.feedback.salonRating, 0);
      avgRating = sum / reviews.length;
    }
    const reviewCount = reviews.length;
    const slide = document.createElement('div');
    let borderClass = '', shadowClass = '', badgeClass = '', crownColor = '';
    if (s.adTier === 'gold') {
      borderClass = 'border-2 border-amber-500';
      shadowClass = 'shadow-[0_0_15px_rgba(245,158,11,0.45)]';
      badgeClass = 'backdrop-blur-md bg-slate-955/80 border border-amber-500/30 text-amber-300';
      crownColor = 'text-yellow-400 drop-shadow-[0_0_5px_rgba(250,204,21,0.7)]';
    } else if (s.adTier === 'silver') {
      borderClass = 'border-2 border-slate-350';
      shadowClass = 'shadow-[0_0_15px_rgba(203,213,225,0.45)]';
      badgeClass = 'backdrop-blur-md bg-slate-955/80 border border-slate-400/30 text-slate-200';
      crownColor = 'text-slate-300 drop-shadow-[0_0_5px_rgba(203,213,225,0.7)]';
    } else if (s.adTier === 'bronze') {
      borderClass = 'border-2 border-amber-800';
      shadowClass = 'shadow-[0_0_15px_rgba(180,83,9,0.45)]';
      badgeClass = 'backdrop-blur-md bg-slate-955/80 border border-amber-700/30 text-amber-600';
      crownColor = 'text-amber-700 drop-shadow-[0_0_5px_rgba(180,83,9,0.7)]';
    }
    
    slide.className = `snap-start flex-shrink-0 w-full h-[140px] rounded-2xl overflow-hidden relative ${borderClass} ${shadowClass} bg-slate-900 cursor-pointer transition-all duration-300 hover:scale-[1.01]`;
    slide.onclick = () => { triggerBooking(s.id); };
    
    const crownIcon = `<i class="fa-solid fa-crown ${crownColor} mr-1.5 animate-pulse text-[9px]"></i>`;
    
    if (s.adBannerUrl) {
      slide.innerHTML = `
        <img src="${s.adBannerUrl}" alt="${s.name} Promotion" class="w-full h-full object-cover">
        <span class="absolute top-2.5 right-2.5 ${badgeClass} text-[9px] px-3 py-1 rounded-full font-bold uppercase tracking-wider flex items-center shadow-lg">
          ${crownIcon}<span>${currentLang === 'en' ? 'Featured' : 'प्रायोजित'}</span>
        </span>
      `;
    } else {
      slide.innerHTML = `
        <div class="relative w-full h-full">
          <img src="${s.image || '/images/default_salon.png'}" class="w-full h-full object-cover">
          <div class="absolute inset-0 bg-gradient-to-t from-slate-955 via-slate-900/40 to-transparent flex flex-col justify-end p-4">
            <h4 class="font-outfit font-bold text-base text-white truncate shadow-sm">${s.name}</h4>
            <div class="flex items-center text-xs text-amber-400 space-x-1.5 mt-1">
              <span class="font-extrabold">${avgRating.toFixed(1)}</span>
              <span class="text-slate-355">★ (${reviewCount})</span>
              <span class="text-slate-400">·</span>
              <span class="text-slate-300 font-medium">${s.address.split(',')[0]}</span>
            </div>
            <p class="text-[10px] text-brand-300 font-semibold mt-1">
              <i class="fa-solid fa-gift mr-1 text-[8px]"></i>${s.offer}
            </p>
          </div>
          <span class="absolute top-2.5 right-2.5 ${badgeClass} text-[9px] px-3 py-1 rounded-full font-bold uppercase tracking-wider flex items-center shadow-lg">
            ${crownIcon}<span>${currentLang === 'en' ? 'Featured' : 'प्रायोजित'}</span>
          </span>
        </div>
      `;
    }
    slider.appendChild(slide);
  });
  startFeaturedSliderAutoPlay();
}

function renderOwnerPromotionStatus(salonId) {
  const s = salonsData.find(salon => salon.id === salonId);
  if (!s) return;
  const count = s.weeklyCompletedCount || 0;
  const progressText = document.getElementById('ownerAdProgressText');
  const progressBar = document.getElementById('ownerAdProgressBar');
  const statusBadge = document.getElementById('ownerAdStatusBadge');
  
  let target = 80;
  if (count >= 100) {
    target = 100;
  } else if (count >= 90) {
    target = 100;
  } else if (count >= 80) {
    target = 90;
  } else {
    target = 80;
  }
  
  if (progressText) {
    progressText.innerText = `${count} / ${target} Completed`;
  }
  
  if (progressBar) {
    const pct = Math.min(100, (count / target) * 100);
    progressBar.style.width = `${pct}%`;
  }
  
  if (statusBadge) {
    if (s.adTier === 'gold') {
      statusBadge.className = "bg-amber-500/10 text-amber-300 border border-amber-500/30 px-2.5 py-0.5 rounded-md font-bold uppercase tracking-wider text-[9px] animate-pulse";
      statusBadge.innerText = t('activeGold');
    } else if (s.adTier === 'silver') {
      statusBadge.className = "bg-slate-350/10 text-slate-200 border border-slate-400/30 px-2.5 py-0.5 rounded-md font-bold uppercase tracking-wider text-[9px] animate-pulse";
      statusBadge.innerText = t('activeSilver');
    } else if (s.adTier === 'bronze') {
      statusBadge.className = "bg-amber-800/15 text-amber-600 border border-amber-700/50 px-2.5 py-0.5 rounded-md font-bold uppercase tracking-wider text-[9px] animate-pulse";
      statusBadge.innerText = t('activeBronze');
    } else {
      statusBadge.className = "bg-slate-900 text-slate-500 border border-slate-800 px-2.5 py-0.5 rounded-md font-bold uppercase tracking-wider text-[9px]";
      statusBadge.innerText = t('inactiveAd');
    }
  }
  
  const input = document.getElementById('ownerAdBannerUrlInput');
  if (input) {
    input.value = s.adBannerUrl || "";
  }
}

async function loadAllDataFromServer() {
  try {
    const [salonsRes, ownersRes, historyRes, gapsRes] = await Promise.all([
      fetch('/api/salons'),
      fetch('/api/owners'),
      fetch('/api/bookings/history'),
      fetch('/api/gaps')
    ]);
    if (salonsRes.ok) salonsData = await salonsRes.json();
    if (ownersRes.ok) ownersData = await ownersRes.json();
    if (historyRes.ok) historyData = await historyRes.json();
    if (gapsRes.ok) queueGaps = await gapsRes.json();
    
    renderSalonsList(salonsData.filter(s => s.status !== 'pending'));
    renderFeaturedSalonsSlider();
    checkUnratedCompletedBookings();
  } catch (e) {
    console.error("Error loading data from server:", e);
  }
}

window.addEventListener('load', async () => {
  try {
    const isLoggedIn = localStorage.getItem('trimora_owner_logged_in') === 'true';
    if (isLoggedIn) {
      loggedInSalonId = localStorage.getItem('trimora_owner_salon_id') || null;
      isSuperAdmin = !loggedInSalonId;
    }
    await loadAllDataFromServer();
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(pos => {
        userLocation = [pos.coords.latitude, pos.coords.longitude];
        renderSalonsList(salonsData.filter(s => s.status !== 'pending'));
        renderMapMarkers(salonsData.filter(s => s.status !== 'pending'));
      }, err => console.log("Using default location:", err));
    }
    initMap();
    loadActiveToken();
    updateLanguageUI();
    setupMobileFormatting();
    checkBookingState();
    checkOwnerAccess();
    populateOwnerSalonDropdown();
    navigateTo('home');
    const urlParams = new URLSearchParams(window.location.search);
    const salonIdParam = urlParams.get('salon');
    if (salonIdParam) {
      setTimeout(() => {
        selectSalon(salonIdParam);
      }, 500);
    }
  } catch (e) {
    console.error("Initialization error:", e);
  }
});


async function rejectSalon(salonId) {
  const confirmMsg = currentLang === 'en' 
    ? "Are you sure you want to delete and block this salon registration?" 
    : "क्या आप वाकई इस सैलून पंजीकरण को हटाना और ब्लॉक करना चाहते हैं?";
  if (!confirm(confirmMsg)) return;
  try {
    const res = await fetch(`/api/salons/${salonId}/reject`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' }
    });
    if (!res.ok) {
      const err = await res.json();
      alert(err.error || "Decline failed");
      return;
    }
    alert(currentLang === 'en' ? "Salon registration deleted and blocked." : "सैलून पंजीकरण हटा दिया गया और ब्लॉक कर दिया गया।");
    
    salonsData = salonsData.filter(s => s.id !== salonId);
    
    renderOwnerApprovals();
    renderSalonsList(salonsData.filter(s => s.status !== 'pending'));
    renderMapMarkers(salonsData.filter(s => s.status !== 'pending'));
    renderFeaturedSalonsSlider();
    populateOwnerSalonDropdown();
  } catch (e) {
    console.error("Error deleting salon:", e);
  }
}

